import { Component, inject, OnInit, ChangeDetectorRef } from '@angular/core';
import { RouterOutlet, RouterLink, RouterLinkActive, Router } from '@angular/router';
import { CommonModule, NgIf, NgFor } from '@angular/common'; // 🚀 AJOUT : Indispensable pour la liste et le badge

@Component({
  selector: 'app-recruiter-layout',
  standalone: true,
  imports: [RouterOutlet, RouterLink, RouterLinkActive, CommonModule, NgIf, NgFor], // 🚀 AJOUT : Modules de template requis
  templateUrl: './recruiter-layout.component.html',
  styles: [`
    /* 📋 CORE CONFIGURATION & RESET */
    .app-container {
      display: flex;
      min-height: 100vh;
      width: 100vw;
      background-color: #f8fafc;
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      margin: 0; position: absolute; top: 0; left: 0;
      overflow: hidden;
    }

    /* 🧭 SIDEBAR LOGICIELLE STYLE SAAS */
    .app-sidebar {
      width: 280px;
      background-color: #0f172a;
      color: #ffffff;
      display: flex;
      flex-direction: column;
      border-right: 1px solid #1e293b;
      z-index: 10;
    }
    
    .sidebar-brand {
      padding: 24px;
      display: flex;
      align-items: center;
      gap: 12px;
      border-bottom: 1px solid #1e293b;
    }
    .logo-icon {
      background-color: #0ea5e9;
      color: #ffffff;
      width: 36px;
      height: 36px;
      border-radius: 8px;
      display: flex;
      justify-content: center;
      align-items: center;
      font-size: 20px;
    }
    .brand-logo, .logo-text { font-size: 22px; font-weight: 800; color: #ffffff; letter-spacing: -0.5px; }
    .logo-text span { color: #0ea5e9; }

    /* Profil d'entreprise dans le menu */
    .recruiter-profile-summary {
      padding: 20px 24px;
      display: flex;
      align-items: center;
      gap: 12px;
      background-color: #1e293b60;
      margin: 15px 15px 5px 15px;
      border-radius: 10px;
    }
    .avatar-circle {
      width: 42px;
      height: 42px;
      background-color: #334155;
      color: #94a3b8;
      border-radius: 50%;
      display: flex;
      justify-content: center;
      align-items: center;
      font-size: 20px;
    }
    .company-name { margin: 0; font-size: 14px; font-weight: 600; color: #f8fafc; }
    .badge-status { font-size: 11px; color: #38bdf8; display: flex; align-items: center; gap: 6px; margin-top: 2px; }
    .dot { width: 6px; height: 6px; background-color: #22c55e; border-radius: 50%; display: inline-block; }

    /* Navigation et Liens */
    .sidebar-nav {
      display: flex;
      flex-direction: column;
      padding: 15px;
      gap: 4px;
      flex: 1;
      overflow-y: auto;
    }
    .nav-section-title {
      font-size: 11px;
      font-weight: 700;
      text-transform: uppercase;
      color: #64748b;
      letter-spacing: 1px;
      margin: 20px 0 8px 12px;
    }
    .nav-link-item {
      display: flex;
      align-items: center;
      padding: 12px 14px;
      color: #94a3b8;
      text-decoration: none;
      font-weight: 500;
      border-radius: 8px;
      font-size: 14px;
      cursor: pointer;
      transition: all 0.15s ease;
    }
    .nav-link-item i { margin-right: 12px; font-size: 18px; color: #64748b; transition: color 0.15s; }
    .nav-link-item:hover, .nav-link-item.active {
      background-color: #1e293b;
      color: #ffffff;
    }
    .nav-link-item.active i, .nav-link-item:hover i { color: #0ea5e9; }
    
    .nav-badge {
      margin-left: auto;
      background-color: #0ea5e920;
      color: #38bdf8;
      font-size: 11px;
      font-weight: 700;
      padding: 2px 8px;
      border-radius: 12px;
    }
    .logout-item { margin-top: auto; color: #ef4444; }
    .logout-item i { color: #ef4444; }
    .logout-item:hover { background-color: #ef444415; color: #f87171; }

    /* 💻 MAIN APPLICATIF */
    .app-main {
      flex: 1;
      display: flex;
      flex-direction: column;
      height: 100vh;
      overflow-y: auto;
    }

    /* 👤 APPLICATION HEADER UPPER DECK */
    .app-header {
      background-color: #ffffff;
      padding: 24px 40px;
      border-bottom: 1px solid #e2e8f0;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    .header-welcome h2 { margin: 0 0 4px 0; color: #0f172a; font-size: 24px; font-weight: 800; letter-spacing: -0.5px; }
    .header-welcome .highlight { color: #0ea5e9; }
    .header-welcome p { margin: 0; color: #64748b; font-size: 14px; }

    .header-actions { display: flex; align-items: center; gap: 20px; }
    .btn-quick-add {
      background-color: #0f172a; color: white; border: none; border-radius: 6px;
      padding: 10px 16px; font-size: 14px; font-weight: 600; cursor: pointer;
      display: flex; align-items: center; gap: 4px; transition: background 0.15s;
    }
    .btn-quick-add:hover { background-color: #1e293b; }
    
    /* 🔔 STYLE DE LA CLOCHE ET DU BADGE ROUGE */
