export class RecruiterLayoutComponent implements OnInit {
  private router = inject(Router);
  private cdr = inject(ChangeDetectorRef); // 🚀 AJOUT : Détecteur de changements Angular
  
  recruiterName = 'Recruteur';
  
  // 🚀 VARIABLES COMPLEMENTAIRES POUR LE TEMPS REEL
  notificationsList: any[] = [];
  unreadCount: number = 0;
  private eventSource: EventSource | null = null;

  ngOnInit() {
    const storedName = localStorage.getItem('name');
    if (storedName) {
      this.recruiterName = storedName;
    }
    
    // 🚀 INITIALISATION DES DEUX FONCTIONS ISOLÉES
    this.loadNotificationHistory();
    this.startLiveNotifications();
  }

  // A. 📥 CHARGEMENT DE L'HISTORIQUE DEPUIS LE CONTROLEUR PARTAGÉ
  loadNotificationHistory() {
    const token = localStorage.getItem('token');
    fetch('http://localhost:3000/api/notifications/history', {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(res => res.ok ? res.json() : { notifications: [] })
    .then(data => {
      this.notificationsList = data.notifications || [];
      this.unreadCount = this.notificationsList.filter(n => !n.is_read || n.is_read === 0).length;
      this.cdr.detectChanges();
    })
    .catch(err => console.error("❌ Erreur chargement historique notifications :", err));
  }

  // B. 📡 BRANCHEMENT SUR LE CANAL SSE EXPRESS EN DIRECT
  startLiveNotifications() {
    const token = localStorage.getItem('token');
    if (!token) return;

    // Ouverture du flux natif
    this.eventSource = new EventSource(`http://localhost:3000/api/notifications/stream?token=${token}`);

    this.eventSource.onmessage = (event) => {
      try {
        const newNotif = JSON.parse(event.data);
        console.log("🔔 [LIVE NOTIF] Alerte reçue instantanément :", newNotif);

        // Ajoute la nouvelle alerte directement au-dessus du tableau
        this.notificationsList.unshift(newNotif);
        this.unreadCount++;
        
        // Indique à Angular de rafraîchir le badge rouge à l'écran
        this.cdr.detectChanges();
      } catch (err) {
        console.error("❌ Erreur traitement JSON de l'événement SSE :", err);
      }
    };

    this.eventSource.onerror = (err) => {
      console.error("⚠️ Connexion flux notifications interrompue. Reconnexion automatique...", err);
    };
  }

  onLogout() {
    // Fermeture propre du flux à la déconnexion
    if (this.eventSource) {
      this.eventSource.close();
    }
    localStorage.clear();
    this.router.navigate(['/login']);
  }
}
